// // This module selects between two 4-bit inputs 'b' and 'a' based on the 1-bit select line 'sel'. When 'sel' is 0, 'y' outputs 'a'; when 'sel' is 1, 'y' outputs 'b'.
module mux_2to1(
    input [3:0] a,
    input [3:0] b,
    input sel,
    output [3:0] y
);

    assign y = sel ? b : a;

endmodule
